INSERT INTO tipo_contrato (nomcontr, descrp) VALUES
('Nombramiento', 'Régimen de carrera administrativa con estabilidad laboral y plaza presupuestada.'),
('Contrato CAS', 'Contrato Administrativo de Servicios bajo el D.L. N.º 1057, sin estabilidad laboral.'),
('Locación de Servicios', 'Contrato civil para prestación de servicios específicos sin vínculo laboral.'),
('Prácticas Preprofesionales', 'Convenio dirigido a estudiantes universitarios o técnicos en formación.'),
('Prácticas Profesionales', 'Convenio para egresados recientes que realizan prácticas supervisadas.'),
('Contrato Suplencia', 'Contrato temporal para cubrir ausencias por licencias, vacaciones o suspensión de labores.'),
('Contrato por Proyecto', 'Contrato de duración limitada vinculado a proyectos con financiamiento específico.'),
('Contrato de Confianza', 'Designación para cargos de confianza con libre remoción.'),
('Contrato Eventual', 'Contrato por necesidad coyuntural o sobrecarga temporal de trabajo.'),
('Contrato por Emergencia', 'Contratación excepcional en casos de desastres naturales o emergencia sanitaria.'),
('Contrato con Organismo Internacional', 'Servicios prestados en coordinación con organismos multilaterales.'),
('Contrato por Promoción Cultural', 'Actividades vinculadas a la difusión y gestión cultural.'),
('Contrato de Mediador Social', 'Facilita procesos de diálogo y resolución de conflictos comunitarios.'),
('Contrato de Servicio Educativo', 'Docencia no regular en programas específicos o cursos cortos.'),
('Contrato con ONG', 'Vinculación para implementación conjunta de proyectos sociales.'),
('Convenio de Voluntariado', 'Participación solidaria sin retribución económica formal.'),
('Contrato de Capacitación', 'Vinculación temporal para procesos de formación o entrenamiento.'),
('Contrato de Monitoreo Externo', 'Seguimiento técnico de programas por agentes independientes.'),
('Contrato de Apoyo a Investigación', 'Participación en proyectos académicos o científicos institucionales.'),
('Contrato de Vinculación Institucional', 'Apoyo a procesos interinstitucionales estratégicos sin relación laboral.');
