create database dbgestpersonal_uni;
use dbgestpersonal_uni;

-- Tabla Personal Universitario 
create table personal_uni(
idpers int auto_increment primary key,
dni char(8) unique,
nompers varchar(100) not null,
apepers varchar(100) not null,
fechnac date,
dirpers varchar(250),
telfpers varchar(9) not null,
correopers varchar(50) not null,
profpers varchar(100) not null,  -- Profesión o titulación
fechingr date,
tipo_personal enum('docente', 'administrativo') not null,  -- Docente o administrativo
departamento varchar(100),  -- Facultad/departamento
escalafon_doc varchar(50),  -- Escalafón para docentes (ej. Principal, Asociado, Auxiliar)
estlab varchar(25)  -- Estado laboral
);

-- Tabla idioma 
create table idioma(
ididi int auto_increment primary key,
nomidi varchar(25) not null
);

-- Tabla idioma_personal 
create table idioma_personal(
idpers int,
ididi int,
nividi varchar(50),
constraint pk_idioma_personal primary key(idpers, ididi),
constraint fk_personal_idi_per foreign key(idpers) references personal_uni(idpers)
ON DELETE CASCADE
ON UPDATE CASCADE,
constraint fk_idioma_idi_per foreign key(ididi) references idioma(ididi)
ON DELETE CASCADE
ON UPDATE CASCADE
);

-- Tabla especialidades 
create table especialidades(
idesp int auto_increment primary key,
nomesp varchar(100) not null
);

-- Tabla especialidades personal
create table especialidad_personal(
idpers int,
idesp int,
instesp varchar(100) not null,
fechesp date,
constraint pk_especialidad_personal primary key(idpers, idesp),
constraint fk_pers_ep foreign key (idpers) references personal_uni(idpers)
ON DELETE CASCADE
ON UPDATE CASCADE,
constraint fk_especialidad_ep foreign key(idesp) references especialidades(idesp)
ON DELETE CASCADE
ON UPDATE CASCADE
);

-- Tabla historia_laboral 
create table historia_laboral(
idhistpers int auto_increment primary key,
idpers int,
inst_lab varchar(250),  -- Institución anterior
cargpers varchar(250),
fechini date,
fechfin date,
foreign key (idpers) references personal_uni(idpers)
ON DELETE CASCADE
ON UPDATE CASCADE
);

-- Tabla certificaciones 
create table certificaciones(
idcertf int auto_increment primary key,
idpers int not null,
nomcertf varchar(250),
fechobt date,
nominst varchar(250),
foreign key (idpers) references personal_uni(idpers)
ON DELETE CASCADE
ON UPDATE CASCADE
);

-- Tabla tipo_tramite 
create table tipo_tramite(
idtptrmt int auto_increment primary key,
nomtrmt varchar(100) not null,
mottrmt varchar (100) not null
);

-- Tabla tramite_personal
create table tramite_personal(
idtrmt int auto_increment primary key,
idpers int not null,
idtptrmt int not null,
fechsoli date not null,
fechini date not null,
fechfin date not null,
esttrmt varchar(50) not null,
obstrmt varchar(250),
foreign key (idpers) references personal_uni(idpers)
ON DELETE CASCADE
ON UPDATE CASCADE,
foreign key (idtptrmt) references tipo_tramite(idtptrmt)
ON DELETE CASCADE
ON UPDATE CASCADE
);

-- Tabla convocatorias_doc
create table convocatorias_doc(
idselec int auto_increment primary key,
nomconv varchar(100) not null,
fechconv date not null,
descrpconv varchar(250) not null,
estconv varchar(25) not null  -- ABIERTA , CERRADA
);

-- Tabla seleccion_personal 
create table postulacion_personal(
idpers int not null,
idselec int not null,
fechpost date,
estpost varchar(100),
pntj int not null,
constraint pk_postulacion_personal primary key (idpers, idselec),
constraint fk_pers_pp foreign key (idpers) references personal_uni(idpers)
ON DELETE CASCADE
ON UPDATE CASCADE,
constraint fk_conv_pp foreign key (idselec) references convocatorias_doc(idselec)
ON DELETE CASCADE
ON UPDATE CASCADE
);

-- Tabla tipo_contrato 
create table tipo_contrato(
idtpcontr int auto_increment primary key,
nomcontr varchar(100) not null,  --  Nombrado, Contratado A, Contratado B1/B2/B3, Hora cátedra
descrp varchar(250),
dedicacion varchar(50)  -- Tiempo completo, medio tiempo, hora cátedra
);

-- Tabla contrato
create table contrato(
idcontr int auto_increment primary key,
idpers int not null,
idtpcontr int not null,
suelpers decimal(10,2) not null,
fechini date,
fechfin date,
foreign key (idpers) references personal_uni(idpers)
ON DELETE CASCADE
ON UPDATE CASCADE,
foreign key (idtpcontr) references tipo_contrato(idtpcontr)
ON DELETE CASCADE
ON UPDATE CASCADE
);

-- Tabla asistencia
create table asistencia(
idasist int auto_increment primary key,
idpers int not null,
fech date,
hrentr1 time,
hrsali1 time,
hrentr2 time,
hrsali2 time,
estasist varchar(100),
unique(idpers, fech),
foreign key (idpers) references personal_uni(idpers)
ON DELETE CASCADE
ON UPDATE CASCADE
);

-- Tabla tipo_licencia
create table tipo_licencia(
idtplic int auto_increment primary key,
nomlic varchar(100)  --  Prenatal, Sabbática, Estudios
);

-- Tabla licencia
create table licencia(
idlic int auto_increment primary key,
idpers int not null,
idtplic int not null,
fechini date,
fechfin date,
justf varchar(250),
foreign key (idpers) references personal_uni(idpers)
ON DELETE CASCADE
ON UPDATE CASCADE,
foreign key (idtplic) references tipo_licencia(idtplic)
ON DELETE CASCADE
ON UPDATE CASCADE
);

-- Tabla tipo_pago
create table tipo_pago(
idtppag int auto_increment primary key,
nompag varchar(100)
);

-- Tabla pagos
create table pagos(
idpag int auto_increment primary key,
idpers int not null,
idtppag int not null,
fechpag datetime default now(),
montpag decimal(10,2) not null,
foreign key (idpers) references personal_uni(idpers)
ON DELETE CASCADE
ON UPDATE CASCADE,
foreign key (idtppag) references tipo_pago(idtppag)
ON DELETE CASCADE
ON UPDATE CASCADE
);

-- Tabla tipo_afp
create table tipo_afp(
idtpafp int auto_increment primary key,
nomafp varchar(100) not null
);

-- Tabla afp
create table afp(
idafp int auto_increment primary key,
idpers int not null,
idtpafp int not null,
montaport decimal(10,2),
fechaport datetime not null,
foreign key (idpers) references personal_uni(idpers)
ON DELETE CASCADE
ON UPDATE CASCADE,
foreign key (idtpafp) references tipo_afp(idtpafp)
ON DELETE CASCADE
ON UPDATE CASCADE
);

-- Tabla capacitador 
create table personal_capacitador(
idperscap int auto_increment primary key,
nomperscap varchar(100) not null,
apeperscap varchar(100) not null,
profperscap varchar(100) not null,
telfperscap char(9)
);

-- Tabla capacitacion
create table capacitacion(
idcap int auto_increment primary key,
idperscap int not null,
idpers int not null,
fechcap date,
temcap varchar(250),
foreign key (idpers) references personal_uni(idpers)
ON DELETE CASCADE
ON UPDATE CASCADE,
foreign key (idperscap) references personal_capacitador(idperscap)
ON DELETE CASCADE
ON UPDATE CASCADE
);

-- Tabla evaluacion
create table evaluacion(
ideval int auto_increment primary key,
idpers int not null,
idcap int not null,
pntj int not null,
fecheval date,
coment varchar(250),
foreign key (idpers) references personal_uni(idpers)
ON DELETE CASCADE
ON UPDATE CASCADE,
foreign key (idcap) references capacitacion(idcap)
ON DELETE CASCADE
ON UPDATE CASCADE
);






