-- ============================================================
-- PUNTO 1: 5 VISTAS CON JOINS
-- ============================================================

-- Vista 1: Datos completos del personal con su contrato activo
create view vw_personal_contrato as
select 
    p.idpers,
    p.dni,
    concat(p.nompers, ' ', p.apepers) as nombre_completo,
    p.tipo_personal,
    p.departamento,
    p.estlab,
    tc.nomcontr as tipo_contrato,
    tc.dedicacion,
    c.suelpers as sueldo,
    c.fechini as inicio_contrato,
    c.fechfin as fin_contrato
from personal_uni p
inner join contrato c on p.idpers = c.idpers
inner join tipo_contrato tc on c.idtpcontr = tc.idtpcontr;

-- Vista 2: Personal con sus idiomas y nivel
create view vw_personal_idiomas as
select 
    p.idpers,
    concat(p.nompers, ' ', p.apepers) as nombre_completo,
    p.tipo_personal,
    p.departamento,
    i.nomidi as idioma,
    ip.nividi as nivel
from personal_uni p
inner join idioma_personal ip on p.idpers = ip.idpers
inner join idioma i on ip.ididi = i.ididi;

-- Vista 3: Asistencia del personal con estado detallado
create view vw_asistencia_personal as
select 
    p.idpers,
    concat(p.nompers, ' ', p.apepers) as nombre_completo,
    p.tipo_personal,
    p.departamento,
    a.fech as fecha,
    a.hrentr1 as entrada,
    a.hrsali1 as salida_1,
    a.hrentr2 as entrada_2,
    a.hrsali2 as salida_2_fin,
    a.estasist as estado_asistencia
from personal_uni p
inner join asistencia a on p.idpers = a.idpers;

-- Vista 4: Pagos con tipo de pago y datos del personal
create view vw_pagos_personal as
select 
    p.idpers,
    concat(p.nompers, ' ', p.apepers) as nombre_completo,
    p.tipo_personal,
    p.departamento,
    tp.nompag as tipo_pago,
    pg.montpag as monto,
    pg.fechpag as fecha_pago
from personal_uni p
inner join pagos pg on p.idpers = pg.idpers
inner join tipo_pago tp on pg.idtppag = tp.idtppag;

-- Vista 5: Capacitaciones con evaluación del personal
create view vw_capacitaciones_evaluaciones as
select 
    p.idpers,
    concat(p.nompers, ' ', p.apepers) as nombre_completo,
    p.tipo_personal,
    concat(pc.nomperscap, ' ', pc.apeperscap) as capacitador,
    c.temcap as tema,
    c.fechcap as fecha_capacitacion,
    e.pntj as puntaje,
    e.coment as comentario,
    e.fecheval as fecha_evaluacion
from personal_uni p
inner join capacitacion c on p.idpers = c.idpers
inner join personal_capacitador pc on c.idperscap = pc.idperscap
left join evaluacion e on e.idpers = p.idpers and e.idcap = c.idcap;

-- ============================================================
-- PUNTO 2: 3 PROCEDIMIENTOS ALMACENADOS (INSERT, UPDATE, DELETE)
-- ============================================================

-- Procedimiento 1: Insertar nuevo personal
delimiter $$
create procedure sp_insertar_personal(
    in p_dni char(8),
    in p_nompers varchar(100),
    in p_apepers varchar(100),
    in p_fechnac date,
    in p_dirpers varchar(250),
    in p_telfpers varchar(9),
    in p_correopers varchar(50),
    in p_profpers varchar(100),
    in p_fechingr date,
    in p_tipo_personal enum('docente','administrativo'),
    in p_departamento varchar(100),
    in p_escalafon_doc varchar(50),
    in p_estlab varchar(25)
)
begin
    values(p_dni, p_nompers, p_apepers, p_fechnac, p_dirpers, p_telfpers, p_correopers, p_profpers, p_fechingr, p_tipo_personal, p_departamento, p_escalafon_doc, p_estlab);
    select last_insert_id() as nuevo_idpers, 'Personal registrado correctamente.' as mensaje;
end;
$$
delimiter ;

-- Procedimiento 2: Actualizar datos del personal
delimiter $$
create procedure sp_actualizar_personal(
    in p_idpers int,
    in p_telfpers varchar(9),
    in p_correopers varchar(50),
    in p_dirpers varchar(250),
    in p_departamento varchar(100),
    in p_estlab varchar(25),
    in p_escalafon_doc varchar(50)
)
begin
    update personal_uni
    set telfpers = p_telfpers,
        correopers = p_correopers,
        dirpers = p_dirpers,
        departamento = p_departamento,
        estlab = p_estlab,
        escalafon_doc = p_escalafon_doc
    where idpers = p_idpers;
    select row_count() as filas_afectadas, 'Personal actualizado correctamente.' as mensaje;
end;
$$
delimiter ;

-- Procedimiento 3: Eliminar personal (solo si no tiene contrato activo)
delimiter $$
create procedure sp_eliminar_personal(
    in p_idpers int
)
begin
    declare v_contratos int;
    select count(*) into v_contratos from contrato where idpers = p_idpers and (fechfin >= curdate() or fechfin is null);
    if v_contratos > 0 then
        select 'No se puede eliminar: el personal tiene un contrato activo.' as mensaje;
    else
        delete from personal_uni where idpers = p_idpers;
        select 'Personal eliminado correctamente.' as mensaje;
    end if;
end;
$$
delimiter ;

-- ============================================================
-- PUNTO 3: 3 PROCEDIMIENTOS ALMACENADOS PARA SELECCIÓN CON PARÁMETROS (JOINS)
-- ============================================================

-- Procedimiento 4: Buscar personal por tipo y estado laboral
delimiter $$
create procedure sp_buscar_personal_tipo_estado(
    in p_tipo_personal enum('docente','administrativo'),
    in p_estlab varchar(25)
)
begin
    select 
        p.idpers,
        p.dni,
        concat(p.nompers, ' ', p.apepers) as nombre_completo,
        p.tipo_personal,
        p.departamento,
        p.estlab,
        tc.nomcontr as tipo_contrato,
        c.suelpers as sueldo,
        c.fechfin as fin_contrato
    from personal_uni p
    left join contrato c on p.idpers = c.idpers
    left join tipo_contrato tc on c.idtpcontr = tc.idtpcontr
    where p.tipo_personal = p_tipo_personal and p.estlab = p_estlab;
end;
$$
delimiter ;

-- Procedimiento 5: Buscar asistencia por persona y rango de fechas
delimiter $$
create procedure sp_buscar_asistencia_rango(
    in p_idpers int,
    in p_fechini date,
    in p_fechfin date
)
begin
    select 
        concat(p.nompers, ' ', p.apepers) as nombre_completo,
        a.fech,
        a.hrentr1,
        a.hrsali1,
        a.hrentr2,
        a.hrsali2,
        a.estasist
    from asistencia a
    inner join personal_uni p on a.idpers = p.idpers
    where a.idpers = p_idpers
      and a.fech between p_fechini and p_fechfin
    order by a.fech;
end;
$$
delimiter ;

-- Procedimiento 6: Buscar pagos por tipo de pago y rango de fechas
delimiter $$
create procedure sp_buscar_pagos_tipo_fecha(
    in p_idtppag int,
    in p_fechini date,
    in p_fechfin date
)
begin
    select 
        concat(p.nompers, ' ', p.apepers) as nombre_completo,
        p.tipo_personal,
        p.departamento,
        tp.nompag as tipo_pago,
        pg.montpag,
        pg.fechpag
    from pagos pg
    inner join personal_uni p on pg.idpers = p.idpers
    inner join tipo_pago tp on pg.idtppag = tp.idtppag
    where pg.idtppag = p_idtppag
      and date(pg.fechpag) between p_fechini and p_fechfin
    order by pg.fechpag desc;
end;
$$
delimiter ;

-- ============================================================
-- PUNTO 4: 3 FUNCIONES CON IF Y CASE
-- ============================================================

-- Función 1: Retorna el estado del contrato del personal
delimiter $$
create function fn_estado_contrato(p_idpers int) 
returns varchar(100)
deterministic
begin
    declare v_fechfin date;
    declare v_mensaje varchar(100);
    select fechfin into v_fechfin from contrato where idpers = p_idpers order by fechfin desc limit 1;
    if v_fechfin is null then
        set v_mensaje = 'Sin contrato registrado';
    elseif v_fechfin < curdate() then
        set v_mensaje = 'Contrato VENCIDO';
    elseif datediff(v_fechfin, curdate()) <= 30 then
        set v_mensaje = 'Contrato por VENCER en menos de 30 días';
    else
        set v_mensaje = 'Contrato VIGENTE';
    end if;
    return v_mensaje;
end;
$$
delimiter ;

-- Función 2: Retorna el estado de asistencia de un personal en el día de hoy
delimiter $$
create function fn_estado_asistencia_hoy(p_idpers int) 
returns varchar(100)
deterministic
begin
    declare v_estado varchar(100);
    select estasist into v_estado from asistencia where idpers = p_idpers and fech = curdate() limit 1;
    
    case 
        when v_estado is null then set v_estado = 'Sin registro de asistencia hoy';
        when v_estado = 'Asistio' then set v_estado = 'Asistencia COMPLETA registrada';
        when v_estado = 'Tardanza' then set v_estado = 'TARDANZA registrada hoy';
        when v_estado = 'Falta' then set v_estado = 'FALTA registrada hoy';
        else set v_estado = concat('Estado: ', v_estado);
    end case;
    return v_estado;
end;
$$
delimiter ;

-- Función 3: Clasifica el rendimiento del personal en capacitaciones
delimiter $$
create function fn_nivel_rendimiento(p_idpers int) 
returns varchar(100)
deterministic
begin
    declare v_promedio decimal(5,2);
    declare v_resultado varchar(100);
    select avg(pntj) into v_promedio from evaluacion where idpers = p_idpers;
    
    if v_promedio is null then
        set v_resultado = 'Sin evaluaciones registradas';
    else
        case 
            when v_promedio >= 90 then set v_resultado = 'Rendimiento EXCELENTE';
            when v_promedio >= 75 then set v_resultado = 'Rendimiento BUENO';
            when v_promedio >= 60 then set v_resultado = 'Rendimiento REGULAR';
            else set v_resultado = 'Rendimiento BAJO - Requiere atención';
        end case;
    end if;
    return v_resultado;
end;
$$
delimiter ;

-- ============================================================
-- PUNTO 5: 4 TRIGGERS DE CONTROL (auditoría en campos sensibles)
-- ============================================================

-- Tabla de auditoría (necesaria para los triggers)
create table if not exists auditoria_bd(
    idaudit int auto_increment primary key,
    tabla_afect varchar(50),
    accion varchar(10),
    idregistro int,
    campo_mod varchar(100),
    valor_ant varchar(250),
    valor_nuevo varchar(250),
    usuario varchar(50),
    fecha_hora datetime default now()
);

-- Trigger 1: Auditar cambios de sueldo en contrato (UPDATE)
delimiter $$
create trigger trg_audit_sueldo_update
before update on contrato
for each row
begin
    if old.suelpers <> new.suelpers then
        values('contrato', 'update', old.idcontr, 'suelpers', old.suelpers, new.suelpers);
    end if;
end;
$$
delimiter ;

-- Trigger 2: Auditar cambio de estado laboral del personal (UPDATE)
delimiter $$
create trigger trg_audit_estlab_update
before update on personal_uni
for each row
begin
    if old.estlab <> new.estlab then
        values('personal_uni', 'update', old.idpers, 'estlab', old.estlab, new.estlab);
    end if;
end;
$$
delimiter ;

-- Trigger 3: Registrar eliminación de contratos
delimiter $$
create trigger trg_audit_contrato_delete
before delete on contrato
for each row
begin
    values('contrato', 'delete', old.idcontr, 'suelpers', old.suelpers, 'ELIMINADO');
end;
$$
delimiter ;

-- Trigger 4: Auditar inserción de pagos (campo sensible: monto)
delimiter $$
create trigger trg_audit_pago_insert
after insert on pagos
for each row
begin
    values('pagos', 'insert', new.idpag, 'montpag', null, new.montpag);
end;
$$
delimiter ;

-- ============================================================
-- PUNTO 6: 5 TRIGGERS SIGNAL (alertas de validación)
-- ============================================================

-- Trigger Signal 1: Impedir DNI duplicado o inválido al insertar personal
delimiter $$
create trigger trg_signal_dni_insert
before insert on personal_uni
for each row
begin
    if length(new.dni) <> 8 then
        signal sqlstate '45000' set message_text = 'ERROR: El DNI debe tener exactamente 8 caracteres.';
    end if;
    if new.fechnac > curdate() then
        signal sqlstate '45000' set message_text = 'ERROR: La fecha de nacimiento no puede ser futura.';
    end if;
end;
$$
delimiter ;

-- Trigger Signal 2: Impedir sueldo negativo o cero en contrato
delimiter $$
create trigger trg_signal_sueldo_insert
before insert on contrato
for each row
begin
    if new.suelpers <= 0 then
        signal sqlstate '45000' set message_text = 'ERROR: El sueldo debe ser mayor a cero.';
    end if;
    if new.fechfin is not null and new.fechfin < new.fechini then
        signal sqlstate '45000' set message_text = 'ERROR: La fecha de fin del contrato no puede ser anterior a la fecha de inicio.';
    end if;
end;
$$
delimiter ;

-- Trigger Signal 3: Validar fechas de licencia
delimiter $$
create trigger trg_signal_licencia_insert
before insert on licencia
for each row
begin
    if new.fechfin < new.fechini then
        signal sqlstate '45000' set message_text = 'ERROR: La fecha de fin de licencia no puede ser anterior a la fecha de inicio.';
    end if;
end;
$$
delimiter ;

-- Trigger Signal 4: Impedir puntaje de evaluación fuera de rango (0-100)
delimiter $$
create trigger trg_signal_evaluacion_insert
before insert on evaluacion
for each row
begin
    if new.pntj < 0 or new.pntj > 100 then
        signal sqlstate '45000' set message_text = 'ERROR: El puntaje de evaluación debe estar entre 0 y 100.';
    end if;
end;
$$
delimiter ;

-- Trigger Signal 5: Impedir asistencia registrada en fecha futura
delimiter $$
create trigger trg_signal_asistencia_insert
before insert on asistencia
for each row
begin
    if new.fech > curdate() then
        signal sqlstate '45000' set message_text = 'ERROR: No se puede registrar asistencia en una fecha futura.';
    end if;
end;
$$
delimiter ;

